// ── ZERO-G WATER in a MONISTARY-style ship hall: raymarched, refractive ──
fn w_h(p: vec3f) -> f32 { return fract(sin(dot(p, vec3f(127.1, 311.7, 74.7))) * 43758.5453); }
fn w_n(p: vec3f) -> f32 {
  let i = floor(p); let f = fract(p); let u = f * f * (3.0 - 2.0 * f);
  return mix(mix(mix(w_h(i), w_h(i + vec3f(1.,0.,0.)), u.x), mix(w_h(i + vec3f(0.,1.,0.)), w_h(i + vec3f(1.,1.,0.)), u.x), u.y),
             mix(mix(w_h(i + vec3f(0.,0.,1.)), w_h(i + vec3f(1.,0.,1.)), u.x), mix(w_h(i + vec3f(0.,1.,1.)), w_h(i + vec3f(1.,1.,1.)), u.x), u.y), u.z);
}
fn w_smin(a: f32, b: f32, k: f32) -> f32 { let h = clamp(0.5 + 0.5 * (b - a) / k, 0.0, 1.0); return mix(b, a, h) - k * h * (1.0 - h); }

// the ship hall: floor, ceiling, side walls, fluted metal columns down z. mat: 1 deck · 2 column · 3 wall
fn w_ship(p0: vec3f) -> vec2f {
  var p = p0;
  let cz = floor(p.z / 4.0); p.z = p.z - (cz + 0.5) * 4.0;
  var d = p.y + 2.2; var m = 1.0;                    // deck
  let dce = 3.4 - p.y; if (dce < d) { d = dce; m = 1.0; }   // ceiling
  let dw = 3.6 - abs(p.x); if (dw < d) { d = dw; m = 3.0; } // side walls
  for (var s = 0; s < 2; s++) {
    let sx = select(-2.6, 2.6, s == 1);
    let q = vec2f(p.x - sx, p.z);
    let ang = atan2(q.y, q.x);
    var dc = length(q) - (0.34 + 0.02 * sin(p.y * 1.1));
    dc += 0.012 * abs(sin(ang * 16.0));              // flutes
    dc = max(dc, -p.y - 2.2); dc = max(dc, p.y - 3.4);
    let cap = max(max(abs(p.x - sx) - 0.5, abs(p.z) - 0.5), abs(p.y - 3.3) - 0.14);
    let base = max(max(abs(p.x - sx) - 0.5, abs(p.z) - 0.5), abs(p.y + 2.05) - 0.16);
    let dcol = min(dc, min(cap, base));
    if (dcol < d) { d = dcol; m = 2.0; }
  }
  return vec2f(d, m);
}

// floating water: metaballs adrift in zero-g (slow, weightless orbits)
fn w_blobs(p: vec3f, t: f32) -> f32 {
  var d = 1e9;
  for (var i = 0; i < 6; i++) {
    let fi = f32(i);
    let c = vec3f(sin(t * (0.19 + fi * 0.05) + fi * 2.4) * 1.7,
                  0.6 + sin(t * (0.15 + fi * 0.04) + fi * 1.7) * 0.95,
                  3.4 + fi * 0.9 + sin(t * (0.13 + fi * 0.03) + fi) * 0.95);
    let r = 0.5 + 0.16 * sin(fi * 1.7);
    d = w_smin(d, length(p - c) - r, 0.6);
  }
  d += 0.025 * w_n(p * 4.0 + vec3f(0.0, 0.0, t * 0.4)) - 0.012;   // surface tension ripple
  return d;
}
fn w_map(p: vec3f, t: f32) -> vec2f {
  let s = w_ship(p);
  let w = w_blobs(p, t);
  if (w < s.x) { return vec2f(w, 9.0); }
  return s;
}
fn w_nrm(p: vec3f, t: f32) -> vec3f {
  let e = vec2f(0.004, 0.0);
  return normalize(vec3f(
    w_map(p + e.xyy, t).x - w_map(p - e.xyy, t).x,
    w_map(p + e.yxy, t).x - w_map(p - e.yxy, t).x,
    w_map(p + e.yyx, t).x - w_map(p - e.yyx, t).x));
}

// strip-light positions repeat down z; used for shading + reflections
fn w_light(p: vec3f, n: vec3f, v: vec3f, t: f32, alb: vec3f, metal: f32) -> vec3f {
  let cz = floor(p.z / 4.0);
  var lit = vec3f(0.02, 0.03, 0.05);      // cool ambient
  for (var lz = 0; lz <= 1; lz++) {
    let zc = (cz + f32(lz) + 0.5) * 4.0;
    let lp = vec3f(0.0, 3.2, zc);
    let L = lp - p; let dist = length(L); let l = L / max(dist, 0.001);
    let atten = 5.5 / (1.0 + dist * dist * 0.5);
    let dif = clamp(dot(n, l), 0.0, 1.0);
    lit += vec3f(0.55, 0.75, 1.0) * dif * atten;
    let r = reflect(-l, n);
    lit += vec3f(0.7, 0.85, 1.0) * pow(clamp(dot(r, v), 0.0, 1.0), mix(20.0, 90.0, metal)) * atten * mix(0.3, 1.6, metal);
  }
  return alb * lit;
}

// shade the SHIP only (used as the environment for water reflect/refract)
fn w_env(ro: vec3f, rd: vec3f, t: f32) -> vec3f {
  var tt = 0.03; var mat = 0.0; var hp = ro;
  for (var i = 0; i < 26; i++) {
    let h = w_ship(ro + rd * tt);
    if (h.x < 0.002 * tt + 0.001) { mat = h.y; hp = ro + rd * tt; break; }
    tt += h.x; if (tt > 22.0) { break; }
  }
  if (mat < 0.5) { return vec3f(0.01, 0.015, 0.03) + vec3f(0.02, 0.04, 0.08) * pow(clamp(rd.y * 0.5 + 0.5, 0.0, 1.0), 2.0); }
  let e = vec2f(0.01, 0.0);
  let n = normalize(vec3f(w_ship(hp + e.xyy).x - w_ship(hp - e.xyy).x, w_ship(hp + e.yxy).x - w_ship(hp - e.yxy).x, w_ship(hp + e.yyx).x - w_ship(hp - e.yyx).x));
  var alb = vec3f(0.20, 0.22, 0.26); var metal = 0.8;
  if (mat < 1.5) { alb = vec3f(0.10, 0.11, 0.13) * (0.7 + 0.3 * step(0.5, fract(hp.x * 2.0))); metal = 0.5; }   // deck panels
  else if (mat > 2.5) { alb = vec3f(0.08, 0.09, 0.11); metal = 0.3; }                                          // wall
  else { alb = vec3f(0.28, 0.30, 0.34); metal = 0.9; }                                                          // column metal
  return w_light(hp, n, -rd, t, alb, metal);
}

fn visual_orchid(uv: vec2f, sdf: f32, color: vec4f, time: f32, params: vec4f, behind: vec4f) -> vec4f {
  let t = time;
  let mx = uni(0); let my = uni(1);
  // camera drifts weightlessly down the hall
  let ro = vec3f(sin(t * 0.12) * 0.5, 0.85, 1.4 + sin(t * 0.08) * 0.25);
  let yaw = mx * 0.4 + sin(t * 0.05) * 0.08;
  let pitch = -my * 0.3 + 0.04;
  var rd = normalize(vec3f(uv.x * 1.1, -uv.y * 1.1 + pitch, 1.35));
  let cy = cos(yaw); let sy = sin(yaw);
  rd = vec3f(rd.x * cy + rd.z * sy, rd.y, -rd.x * sy + rd.z * cy);

  var tt = 0.03; var mat = 0.0; var hp = ro;
  for (var i = 0; i < 80; i++) {
    let h = w_map(ro + rd * tt, t);
    if (h.x < 0.0015 * tt + 0.0007) { mat = h.y; hp = ro + rd * tt; break; }
    tt += h.x * 0.9; if (tt > 24.0) { break; }
  }

  var col = vec3f(0.01, 0.015, 0.03);
  if (mat > 8.5) {
    // WATER — fresnel reflect + refract, cyan absorption, sharp glint
    let n = w_nrm(hp, t); let v = -rd;
    let fres = 0.03 + 0.97 * pow(clamp(1.0 - dot(n, v), 0.0, 1.0), 5.0);
    let refl = w_env(hp + n * 0.03, reflect(rd, n), t);
    let rr = refract(rd, n, 1.0 / 1.33);
    var refr = w_env(hp - n * 0.03, rr, t);
    refr *= vec3f(0.72, 0.90, 0.96);                         // water tint / absorption
    col = mix(refr, refl, fres);
    // sun glint off the surface
    let lp = vec3f(0.0, 3.2, (floor(hp.z / 4.0) + 0.5) * 4.0);
    let l = normalize(lp - hp);
    col += vec3f(1.0, 1.0, 0.95) * pow(clamp(dot(reflect(-l, n), v), 0.0, 1.0), 240.0) * 1.4;
    col += vec3f(0.15, 0.35, 0.5) * pow(clamp(1.0 - dot(n, v), 0.0, 1.0), 3.0) * 0.4;   // rim sheen
  } else if (mat > 0.5) {
    let n = w_nrm(hp, t); let v = -rd;
    var alb = vec3f(0.28, 0.30, 0.34); var metal = 0.85;
    if (mat < 1.5) { alb = vec3f(0.10, 0.11, 0.13) * (0.7 + 0.3 * step(0.5, fract(hp.x * 2.0))); metal = 0.5; }
    else if (mat > 2.5) { alb = vec3f(0.08, 0.09, 0.11); metal = 0.3; }
    col = w_light(hp, n, v, t, alb, metal);
    // wet metal picks up a faint reflection of the hall
    if (metal > 0.6) { col += w_env(hp + n * 0.03, reflect(rd, n), t) * 0.15; }
  }

  // strip lights glowing in air (volumetric-ish)
  {
    let cz0 = floor(ro.z / 4.0);
    for (var fz = 0; fz < 4; fz++) {
      let zc = (cz0 + f32(fz) + 0.5) * 4.0;
      let lp = vec3f(0.0, 3.2, zc); let toL = lp - ro; let proj = dot(toL, rd);
      if (proj > 0.2 && proj < tt + 0.5) {
        let perp = length(toL - rd * proj);
        col += vec3f(0.4, 0.6, 1.0) * exp(-perp * perp * 40.0) * 0.6 / (1.0 + proj * proj * 0.15);
      }
    }
  }
  col = pow(clamp(col, vec3f(0.0), vec3f(6.0)), vec3f(0.85)) * 1.15;   // exposure
  return vec4f(col, 1.0);
}
